   104	        ) -> Result<Vec<(TableReference, Arc<dyn TableProvider>)>> {
   105	            let mut schema_collector = Self::new(consumer);
   106	
   107	            for plan_rel in plan.relations.iter() {
   108	                let rel_type = plan_rel
   109	                    .rel_type
   110	                    .as_ref()
   111	                    .ok_or(substrait_datafusion_err!("PlanRel must set rel_type"))?;
   112	                match rel_type {
